const output = $input.first().json.output;
const user = $('Loop Over Users').item.json;
const resumen = $('EXTRACTOR RESPONSE').item.json.conversation_ressume;

return [{
  json: {
    manychat_id: user.manychat_id,
    nombre: user.nombre || 'Desconocido',
    proyecto: user.proyecto || null,
    fecha_analisis: $now.toISO(),
    resumen_conversacion: resumen || null,
    funnel_stage: output.funnel_stage || null,
    intencion_detectada: output.intencion_detectada || null,
    tools_correctas: output.tools_correctas || null,
    errores_detectados: output.errores_detectados || null,
    oportunidades_perdidas: output.oportunidades_perdidas || null,
    tono_agente: output.tono_agente || null,
    puntuacion: Number(output.puntuacion) || null,
    recomendacion: output.recomendacion || null
  }
}];
